/**
 * protocol69-cascade.verify.ts — runnable verification of the jet-engine compressor
 * cascade product law for the protocol69 teleport cache-skip stage (OSI L5 / session).
 *
 * Run:  pnpm run gnode -- run open-source/gnosis/src/protocol69-cascade.verify.ts
 *
 * Asserts:
 *   1. The protocol69 teleport cascade overall ratio = product of its stage ratios
 *      (Gnosis.MathJetEngine.overallRatio): 1 (gate) × 9 (cache-skip) = 9.
 *   2. The append homomorphism: stacking the gate-cascade and the cache-skip-cascade
 *      multiplies their overall ratios (Gnosis.MathJetEngine.overallRatio_append).
 *   3. The measured end-to-end equals the predicted product exactly (residual 1),
 *      because the cache-skip ratio is a deterministic byte ratio (288/32).
 */

import {
  protocol69CascadeStages,
  protocol69CompressorCascade,
  PROTOCOL69_ENVELOPE_BYTES,
  PROTOCOL69_TELEPORT_HIT_OUTPUT_BYTES,
  PROTOCOL69_TELEPORT_CACHE_SKIP_RATIO,
  PROTOCOL69_ADMISSION_GATE_RATIO,
  stage,
  overallRatio,
  compose,
  homomorphismHolds,
  lawHolds,
  summarize,
} from './protocol69';

function assert(cond: boolean, msg: string): void {
  if (!cond) {
    throw new Error(`ASSERT FAILED: ${msg}`);
  }
}

console.log('protocol69 teleport compressor cascade — OSI L5 (session) cache-skip stage');
console.log('');
console.log('honest ratio source (byte sizes, from the real wire + teleport payload):');
console.log(`  cache-key wire envelope  = ${PROTOCOL69_ENVELOPE_BYTES} bytes  (PROTOCOL69_ENVELOPE_LEN, protocol69.rs)`);
console.log(
  `  frozen-compute HIT output = ${PROTOCOL69_TELEPORT_HIT_OUTPUT_BYTES} bytes  ((tail_residual 8 + kv_slab 64) f32 x 4, teleport.rs)`,
);
console.log(
  `  cache-skip ratio          = ${PROTOCOL69_TELEPORT_HIT_OUTPUT_BYTES} / ${PROTOCOL69_ENVELOPE_BYTES} = ${PROTOCOL69_TELEPORT_CACHE_SKIP_RATIO}x`,
);
console.log(`  admission-gate ratio      = ${PROTOCOL69_ADMISSION_GATE_RATIO}x (clean pass-through, cascade identity)`);
console.log('');

// --- 1. overall ratio = product of stage ratios -----------------------------
const stages = protocol69CascadeStages();
const overall = overallRatio(stages);
const product = stages.reduce((acc, s) => acc * s.ratio, 1);
assert(overall === product, 'overallRatio must equal the product of stage ratios');
assert(overall === 9, `expected overall 9x (1 x 9), got ${overall}`);
console.log(`[1] overallRatio = product: ${stages.map((s) => `${s.name}=${s.ratio}x`).join(' * ')} = ${overall}x  OK`);

// --- 2. append homomorphism: stacking multiplies ----------------------------
const gateOnly = [stage('p69-admission-gate', PROTOCOL69_ADMISSION_GATE_RATIO)];
const skipOnly = [stage('p69-teleport-cache-skip', PROTOCOL69_TELEPORT_CACHE_SKIP_RATIO)];
const stacked = compose(gateOnly, skipOnly);
assert(homomorphismHolds(gateOnly, skipOnly), 'append homomorphism must hold for gate ++ cache-skip');
assert(
  overallRatio(stacked) === overallRatio(gateOnly) * overallRatio(skipOnly),
  'overall(compose(a,b)) must equal overall(a) * overall(b)',
);
console.log(
  `[2] overallRatio_append: overall(gate ++ skip)=${overallRatio(stacked)}x == ${overallRatio(gateOnly)}x * ${overallRatio(skipOnly)}x  OK`,
);

// --- 3. measured end-to-end == predicted product (residual 1) ---------------
const report = protocol69CompressorCascade();
assert(lawHolds(report), 'product law must predict the measured end-to-end exactly');
assert(report.predictedProduct === 9 && report.measuredEndToEnd === 9, 'predicted and measured must both be 9x');
console.log(`[3] product law predicts end-to-end: ${summarize(report)}  OK`);
console.log('');
console.log('theorem IDs:');
for (const id of report.theoremIds) {
  console.log(`  - ${id}`);
}
console.log('');
console.log('ALL protocol69 teleport cascade assertions passed.');
